// alcoholic-beverage.service.ts (SEMPLIFICATO)
import { Injectable, inject } from '@angular/core';
import { BaseService } from '../Base/base.service';
import { BehaviorSubject, combineLatest, map } from 'rxjs';

export interface AlcoholicBeverage {
  id: string;
  restaurant_id: string;
  name: string;
  description?: string;
  category: string; // Questo campo DEVE esistere nelle bevande
  producer?: string;
  region?: string;
  vintage?: number;
  alcohol_percentage?: number;
  bottle_format?: string;
  cost_per_unit: number;
  price: number;
  current_stock: number;
  minimum_stock: number;
  is_active: boolean;
  is_available: boolean;
  display_in_menu: boolean;
  menu_position: number;
  rating?: number;
  image_url?: string;
  created_at: string;
  updated_at: string;
  alert_enabled: boolean;
  to_buy: boolean;
}

export interface BeverageStats {
  total: number;
  active: number;
  inventoryValue: number;
  averagePrice: number;
  lowStockCount: number;
}

