@Injectable({
  providedIn: 'root'
})
export class AlcoholicBeverageService extends BaseService<AlcoholicBeverage> {
  
  public statsSubject = new BehaviorSubject<BeverageStats>({
    total: 0,
    active: 0,
    inventoryValue: 0,
    averagePrice: 0,
    lowStockCount: 0
  });
  stats$ = this.statsSubject.asObservable();

  // Esponi le categorie predefinite come observable
  private categoriesSubject = new BehaviorSubject<any[]>(PREDEFINED_BEVERAGE_CATEGORIES);
  categories$ = this.categoriesSubject.asObservable();

  // Observable combinato con categorie
  beveragesWithCategories$ = combineLatest([
    this.data$,
    this.categories$
  ]).pipe(
    map(([beverages, categories]) => {
      // Calcola statistiche
      this.calculateStats(beverages);
      
      // Aggiorna i conteggi per ogni categoria
      const updatedCategories = categories.map(category => ({
        ...category,
        count: beverages.filter(b => b.category === category.value).length
      }));
      
      return { beverages, categories: updatedCategories };
    })
  );

  override getTableName(): string {
    return 'beverages'; // Tabella corretta
  }

  constructor() {
    super();
    
    // Quando i dati cambiano, aggiorna i conteggi
    this.data$.subscribe(beverages => {
      this.updateCategoryCounts(beverages);
    });
  }

  // Aggiorna i conteggi delle categorie in base alle bevande
  private updateCategoryCounts(beverages: AlcoholicBeverage[]): void {
    const currentCategories = this.categoriesSubject.value;
    const updatedCategories = currentCategories.map(category => ({
      ...category,
      count: beverages.filter(b => b.category === category.value).length
    }));
    this.categoriesSubject.next(updatedCategories);
  }

  // Ottieni tutte le categorie (sincrono)
  getCategories(): any[] {
    return this.categoriesSubject.value;
  }

  // Ottieni categoria per valore
  getCategoryByValue(value: string): any {
    return this.categoriesSubject.value.find(c => c.value === value) || 
           { value: 'altro', label: 'Altro', icon: 'local_bar', color: '#6B7280' };
  }

  // Filtra bevande
  filterBeverages(filters: {
    search?: string;
    category?: string;
    minPrice?: number;
    maxPrice?: number;
    inStock?: boolean;
  } = {}): AlcoholicBeverage[] {
    let filtered = this.data;

    if (filters.category) {
      filtered = filtered.filter(b => b.category === filters.category);
    }

    if (filters.search) {
      const term = filters.search.toLowerCase();
      filtered = filtered.filter(b =>
        b.name.toLowerCase().includes(term) ||
        b.producer?.toLowerCase().includes(term) ||
        b.region?.toLowerCase().includes(term) ||
        b.description?.toLowerCase().includes(term)
      );
    }

    if (filters.minPrice !== undefined) {
      filtered = filtered.filter(b => b.price >= filters.minPrice!);
    }

    if (filters.maxPrice !== undefined) {
      filtered = filtered.filter(b => b.price <= filters.maxPrice!);
    }

    if (filters.inStock !== undefined) {
      filtered = filtered.filter(b => 
        filters.inStock ? b.current_stock > 0 : b.current_stock === 0
      );
    }

    return filtered;
  }

  // Ordina bevande
  sortBeverages(
    beverages: AlcoholicBeverage[],
    sortBy: 'name' | 'price_asc' | 'price_desc' | 'stock'
  ): AlcoholicBeverage[] {
    const sorted = [...beverages];
    
    switch (sortBy) {
      case 'name':
        return sorted.sort((a, b) => a.name.localeCompare(b.name));
      case 'price_asc':
        return sorted.sort((a, b) => a.price - b.price);
      case 'price_desc':
        return sorted.sort((a, b) => b.price - a.price);
      case 'stock':
        return sorted.sort((a, b) => b.current_stock - a.current_stock);
      default:
        return sorted;
    }
  }

  // Aggiorna stock
  async updateStock(beverageId: string, delta: number): Promise<boolean> {
    const beverage = this.data.find(b => b.id === beverageId);
    if (!beverage) return false;

    const newStock = Math.max(0, beverage.current_stock + delta);
    
    return await this.update(beverageId, {
      current_stock: newStock,
      is_available: newStock > 0,
      to_buy: newStock <= beverage.minimum_stock,
      updated_at: new Date().toISOString()
    });
  }

  // Crea bevanda (controlla categoria valida)
  async createBeverage(data: Partial<AlcoholicBeverage>): Promise<AlcoholicBeverage | null> {
    // Verifica che la categoria sia valida
    if (data.category) {
      const validCategory = this.categoriesSubject.value.find(c => c.value === data.category);
      if (!validCategory) {
        console.error('❌ Categoria non valida:', data.category);
        // Assegna categoria "altro" se non valida
        data.category = 'altro';
      }
    } else {
      // Se non specificata, usa "altro"
      data.category = 'altro';
    }

    return await this.create(data);
  }

  // Aggiorna bevanda (controlla categoria valida)
  async updateBeverage(id: string, data: Partial<AlcoholicBeverage>): Promise<boolean> {
    // Verifica che la categoria sia valida
    if (data.category) {
      const validCategory = this.categoriesSubject.value.find(c => c.value === data.category);
      if (!validCategory) {
        console.error('❌ Categoria non valida:', data.category);
        data.category = 'altro';
      }
    }

    return await this.update(id, data);
  }

  // Calcola statistiche
  private calculateStats(beverages: AlcoholicBeverage[]): void {
    const stats: BeverageStats = {
      total: beverages.length,
      active: beverages.filter(b => b.is_active).length,
      inventoryValue: beverages.reduce((sum, b) => sum + (b.cost_per_unit * b.current_stock), 0),
      averagePrice: beverages.length > 0 
        ? beverages.reduce((sum, b) => sum + b.price, 0) / beverages.length 
        : 0,
      lowStockCount: beverages.filter(b => b.current_stock <= b.minimum_stock).length
    };

    this.statsSubject.next(stats);
  }
}