// alcoholic-beverages.component.ts (MODIFICATO)
import { Component, OnInit, OnDestroy, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Subscription } from 'rxjs';
import { AlcoholicBeverage, AlcoholicBeverageService } from '../../../services/Piatti/alcoholic.service';
import { LucideAngularModule } from 'lucide-angular';

interface Category {
  value: string;
  label: string;
  icon: string;
  color: string;
  count: number;
}

interface StockStatus {
  class: string;
  text: string;
}

@Component({
  selector: 'app-alcoholic-beverages',
  templateUrl: './alcoholic-beverages.html',
  styleUrls: ['./alcoholic-beverages.css'],
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule]
})
export class AlcoholicBeverages implements OnInit, OnDestroy {
  // Servizi
  private beverageService = inject(AlcoholicBeverageService);
  private subscriptions: Subscription[] = [];

  // Dati
  allBeverages: AlcoholicBeverage[] = [];
  filteredBeverages: AlcoholicBeverage[] = [];
  categories: Category[] = [];
  
  // Statistiche
  totalProducts: number = 0;
  activeProducts: number = 0;
  inventoryValue: number = 0;
  averagePrice: number = 0;
  lowStockCount: number = 0;
  categoriesCount: number = 0; // AGGIUNGI QUESTA
  
  // Filtri
  searchTerm: string = '';
  selectedCategory: string = '';
  sortBy: 'name' | 'price_asc' | 'price_desc' | 'stock' = 'name';
  showAvailableOnly: boolean = false;
  showLowStockOnly: boolean = false;
  
  // Stato
  isLoading: boolean = true;
  
  // Modal
  showAddModal: boolean = false;
  showEditModal: boolean = false;
  showConfirmModal: boolean = false;
  
  // Form
  beverageForm: Partial<AlcoholicBeverage> = this.getEmptyBeverageForm();
  
  // Variabili di supporto
  currentYear = new Date().getFullYear(); // AGGIUNGI QUESTA
  beverageToDeleteId: string | null = null;
  editingBeverage: AlcoholicBeverage | null = null;

  ngOnInit(): void {
    this.loadData();
    this.subscribeToData();
  }

  ngOnDestroy(): void {
    this.subscriptions.forEach(sub => sub.unsubscribe());
  }

  // Sottoscrizione ai dati
  subscribeToData(): void {
    const sub1 = this.beverageService.beveragesWithCategories$.subscribe(
      ({ beverages, categories }) => {
        this.allBeverages = beverages;
        this.categories = categories;
        this.categoriesCount = categories.length; // AGGIORNA IL CONTATORE
        
        console.log('📋 Categorie caricate:', this.categories.length);
        console.log('🍺 Bevande caricate:', this.allBeverages.length);
        
        // Aggiorna statistiche
        this.updateStatistics();
        
        // Applica filtri
        this.applyFilters();
        
        this.isLoading = false;
      },
      error => {
        console.error('Error loading beverages:', error);
        this.isLoading = false;
      }
    );

    const sub2 = this.beverageService.stats$.subscribe(stats => {
      if (stats) {
        this.totalProducts = stats.total;
        this.activeProducts = stats.active;
        this.inventoryValue = stats.inventoryValue;
        this.averagePrice = stats.averagePrice;
        this.lowStockCount = stats.lowStockCount;
      }
    });

    this.subscriptions.push(sub1, sub2);
  }

  // Carica dati iniziali
  loadData(): void {
    this.isLoading = true;
    this.beverageService.loadData();
  }

  // Gestione filtri
  onSearchChange(value: string): void {
    this.searchTerm = value;
    this.applyFilters();
  }

  onCategoryFilterChange(value: string): void {
    this.selectedCategory = value;
    this.applyFilters();
  }

  onSortChange(value: string): void {
    this.sortBy = value as any;
    this.applyFilters();
  }

  toggleAvailableFilter(): void {
    this.showAvailableOnly = !this.showAvailableOnly;
    this.applyFilters();
  }

  toggleLowStockFilter(): void {
    this.showLowStockOnly = !this.showLowStockOnly;
    this.applyFilters();
  }

  // Applica tutti i filtri
  applyFilters(): void {
    let filtered = [...this.allBeverages];
    
    // Filtro per ricerca
    if (this.searchTerm.trim()) {
      const term = this.searchTerm.toLowerCase();
      filtered = filtered.filter(b =>
        b.name.toLowerCase().includes(term) ||
        b.producer?.toLowerCase().includes(term) ||
        b.region?.toLowerCase().includes(term) ||
        b.description?.toLowerCase().includes(term)
      );
    }
    
    // Filtro per categoria
    if (this.selectedCategory) {
      filtered = filtered.filter(b => b.category === this.selectedCategory);
    }
    
    // Filtro per disponibilità
    if (this.showAvailableOnly) {
      filtered = filtered.filter(b => b.is_available && b.current_stock > 0);
    }
    
    // Filtro per scorte basse
    if (this.showLowStockOnly) {
      filtered = filtered.filter(b => b.current_stock <= b.minimum_stock);
    }
    
    // Ordina
    this.filteredBeverages = this.beverageService.sortBeverages(filtered, this.sortBy);
  }

  // Form bevanda vuoto
  getEmptyBeverageForm(): Partial<AlcoholicBeverage> {
    return {
      name: '',
      category: this.categories[0]?.value || 'vino_rosso',
      price: 0,
      cost_per_unit: 0,
      current_stock: 0,
      minimum_stock: 10,
      alcohol_percentage: 13,
      bottle_format: '750ml',
      is_active: true,
      is_available: true,
      display_in_menu: true,
      alert_enabled: true,
      to_buy: false,
      menu_position: 0
    };
  }

  // Aggiungi bevanda
  async addBeverage(): Promise<void> {
    if (!this.validateBeverageForm()) return;
    
    try {
      const result = await this.beverageService.createBeverage(this.beverageForm);
      if (result) {
        this.showAddModal = false;
        this.resetBeverageForm();
      } else {
        alert('Errore nella creazione della bevanda');
      }
    } catch (error) {
      console.error('Error adding beverage:', error);
      alert('Errore nella creazione della bevanda');
    }
  }

  // Modifica bevanda
  editBeverage(beverage: AlcoholicBeverage): void {
    this.editingBeverage = beverage;
    this.beverageForm = { ...beverage };
    this.showEditModal = true;
  }

  // Aggiorna bevanda
  async updateBeverage(): Promise<void> {
    if (!this.validateBeverageForm() || !this.editingBeverage) return;
    
    try {
      const result = await this.beverageService.updateBeverage(
        this.editingBeverage.id, 
        this.beverageForm
      );
      
      if (result) {
        this.showEditModal = false;
        this.resetBeverageForm();
      } else {
        alert('Errore nell\'aggiornamento della bevanda');
      }
    } catch (error) {
      console.error('Error updating beverage:', error);
      alert('Errore nell\'aggiornamento della bevanda');
    }
  }

  // Elimina bevanda
  deleteBeverage(beverageId: string): void {
    this.beverageToDeleteId = beverageId;
    this.showConfirmModal = true;
  }

  // Conferma eliminazione
  async confirmDelete(): Promise<void> {
    if (!this.beverageToDeleteId) return;
    
    try {
      const result = await this.beverageService.delete(this.beverageToDeleteId);
      if (result) {
        this.showConfirmModal = false;
        this.beverageToDeleteId = null;
      } else {
        alert('Errore nell\'eliminazione della bevanda');
      }
    } catch (error) {
      console.error('Error deleting beverage:', error);
      alert('Errore nell\'eliminazione della bevanda');
    }
  }

  // Aggiorna stock
  async updateStock(beverageId: string, delta: number): Promise<void> {
    try {
      await this.beverageService.updateStock(beverageId, delta);
    } catch (error) {
      console.error('Error updating stock:', error);
      alert('Errore nell\'aggiornamento dello stock');
    }
  }

  // Validazione form bevanda
  validateBeverageForm(): boolean {
    if (!this.beverageForm.name?.trim()) {
      alert('Il nome della bevanda è obbligatorio');
      return false;
    }
    
    if (!this.beverageForm.category) {
      alert('Seleziona una categoria');
      return false;
    }
    
    if (!this.beverageForm.price || this.beverageForm.price <= 0) {
      alert('Inserisci un prezzo valido');
      return false;
    }
    
    return true;
  }

  // Reset form bevanda
  resetBeverageForm(): void {
    this.beverageForm = this.getEmptyBeverageForm();
    this.editingBeverage = null;
  }

  // Chiudi modal bevanda
  closeBeverageModal(): void {
    this.showAddModal = false;
    this.showEditModal = false;
    this.resetBeverageForm();
  }

  // Helper functions per template
  getCategoryLabel(categoryValue: string): string {
    const category = this.categories.find(c => c.value === categoryValue);
    return category?.label || categoryValue;
  }

  getCategoryIcon(categoryValue: string): string {
    const category = this.categories.find(c => c.value === categoryValue);
    return category?.icon || 'local_bar';
  }

  getCategoryColor(categoryValue: string): string {
    const category = this.categories.find(c => c.value === categoryValue);
    return category?.color || '#6B7280';
  }

  getStockColor(beverage: AlcoholicBeverage): string {
    if (beverage.current_stock === 0) return '#FF6B6B';
    if (beverage.current_stock <= beverage.minimum_stock) return '#FFA726';
    return '#4CAF50';
  }

  getStockPercentage(beverage: AlcoholicBeverage): number {
    const max = Math.max(beverage.current_stock, beverage.minimum_stock * 2);
    return Math.min((beverage.current_stock / max) * 100, 100);
  }

  getStockStatus(beverage: AlcoholicBeverage): StockStatus {
    if (beverage.current_stock === 0) {
      return { class: 'chip-error', text: 'Esaurito' };
    } else if (beverage.current_stock <= beverage.minimum_stock) {
      return { class: 'chip-warning', text: 'Scorta bassa' };
    } else {
      return { class: 'chip-success', text: 'Disponibile' };
    }
  }

  formatPrice(price: number): string {
    return price.toFixed(2).replace('.', ',');
  }

  formatNumber(value: number): string {
    return value.toFixed(2).replace('.', ',');
  }

  // Aggiorna statistiche
  updateStatistics(): void {
    this.totalProducts = this.allBeverages.length;
    this.activeProducts = this.allBeverages.filter(b => b.is_active).length;
    this.inventoryValue = this.allBeverages.reduce((sum, b) => sum + (b.cost_per_unit * b.current_stock), 0);
    this.averagePrice = this.allBeverages.length > 0 
      ? this.allBeverages.reduce((sum, b) => sum + b.price, 0) / this.allBeverages.length 
      : 0;
    this.lowStockCount = this.allBeverages.filter(b => b.current_stock <= b.minimum_stock).length;
  }
}